"""Design assets for the HTML dashboard (generated from the design swarm).

CSS, tooltip JS, and plain-language copy are embedded as literals so the report
is self-contained and readable by non-bioinformaticians. Regenerate rather than
hand-editing.
"""

from __future__ import annotations

DASHBOARD_CSS = "/* ============================================================================\n   omicau dashboard \u2014 unified editorial design system (drop-in <style> body)\n   Replaces reporter.py lines 419-498. NO font @import (Google Fonts <link> exists).\n   Palette: Okabe-Ito, color-blind-safe. Every colour pairs with a word or glyph.\n   Fonts: EB Garamond (prose) + JetBrains Mono (numbers/code).\n   Preserves every class the Python emits; adds the explanatory layer.\n   ONE tooltip system (.info), ONE badge system (.badge--*), ONE callout, one\n   collapsible glossary. No parallel .tip-*/.status/.chip/.exec-hero variants.\n   ========================================================================== */\n\n/* ---- Design tokens ------------------------------------------------------- */\n:root{\n  --cobalt:#0072B2;      /* standard / good / optimal / clean data   */\n  --vermillion:#D55E00;  /* warning / confounder / risk              */\n  --amber:#E69F00;       /* caution                                  */\n  --teal:#009E73;        /* positive / added value (fusion helps)    */\n  --slate:#4477AA;       /* neutral / single-modality / redundant    */\n\n  --cobalt-ink:#005E93; --vermillion-ink:#B34E00; --amber-ink:#8A5E00;\n  --teal-ink:#007A59;   --slate-ink:#3A6491;      /* all >=4.5:1 on white */\n\n  --cobalt-bg:#E9F1F8;     --cobalt-line:#B7D5E9;\n  --vermillion-bg:#FBEBE0; --vermillion-line:#F1C6A8;\n  --amber-bg:#FBF2DB;      --amber-line:#ECD69C;\n  --teal-bg:#E3F3EC;       --teal-line:#A9DECB;\n  --slate-bg:#ECF0F6;      --slate-line:#C6D3E4;\n\n  --ink:#1A202C; --ink-soft:#2D3748; --muted:#64748B; --faint:#94A3B8;\n  --border:#E2E8F0; --hairline:#EDF1F5; --bg:#FBFCFD; --panel:#FFFFFF; --sunken:#F7FAFC;\n  --code-bg:#0F172A; --code-ink:#E2E8F0;\n\n  --serif:'EB Garamond',Georgia,'Times New Roman',serif;\n  --mono:'JetBrains Mono','Fira Code','SF Mono',ui-monospace,monospace;\n\n  --s1:4px; --s2:8px; --s3:12px; --s4:16px; --s5:24px; --s6:32px; --s7:48px; --s8:64px;\n  --r1:8px; --r2:12px; --r3:16px; --r-pill:999px;\n  --shadow-1:0 1px 2px rgba(15,23,42,.04);\n  --shadow-2:0 6px 24px rgba(15,23,42,.10),0 1px 3px rgba(15,23,42,.06);\n  --measure:70ch;\n}\n\n/* ---- Reset / base -------------------------------------------------------- */\n*{box-sizing:border-box}\nhtml{-webkit-text-size-adjust:100%}\nbody{margin:0;background:var(--bg);color:var(--ink);font-family:var(--serif);\n  font-size:18px;line-height:1.65;font-feature-settings:\"kern\" 1,\"liga\" 1;\n  -webkit-font-smoothing:antialiased;text-rendering:optimizeLegibility}\np{margin:0 0 var(--s4)} p:last-child{margin-bottom:0}\na{color:var(--cobalt-ink);text-underline-offset:2px} strong{font-weight:600}\n::selection{background:var(--cobalt-bg);color:var(--ink)}\n:focus-visible{outline:2px solid var(--cobalt);outline-offset:2px;border-radius:3px}\n.wrap{max-width:1180px;margin:0 auto;padding:0 var(--s5) var(--s8)}\n\n/* ---- Masthead ------------------------------------------------------------ */\nheader.masthead{border-bottom:1px solid var(--border);padding:var(--s7) 0 var(--s5);margin-bottom:var(--s2)}\n.brand{font-family:var(--mono);font-weight:600;font-size:12.5px;letter-spacing:.24em;\n  text-transform:uppercase;color:var(--cobalt)}\nh1{font-size:clamp(30px,4.4vw,42px);font-weight:600;line-height:1.12;letter-spacing:-.015em;\n  margin:var(--s3) 0 var(--s2);color:var(--ink)}\n.sub{color:var(--muted);font-size:17px}\n.hashline{font-family:var(--mono);font-size:12px;color:var(--muted);margin-top:var(--s3);word-break:break-all}\n\n/* ---- Tabs ---------------------------------------------------------------- */\n.tabs{display:flex;gap:var(--s1);border-bottom:1px solid var(--border);margin:var(--s5) 0 var(--s6);\n  position:sticky;top:0;z-index:5;background:linear-gradient(var(--bg) 72%,rgba(251,252,253,0));padding-top:var(--s2)}\n.tab{appearance:none;border:none;background:none;font-family:var(--serif);font-size:18px;color:var(--muted);\n  padding:var(--s3) var(--s4);cursor:pointer;border-bottom:2px solid transparent;\n  transition:color .15s ease,border-color .15s ease}\n.tab:hover{color:var(--ink-soft)}\n.tab.active{color:var(--ink);border-bottom-color:var(--cobalt);font-weight:600}\n.panel{display:none;animation:fade .25s ease} .panel.active{display:block}\n@keyframes fade{from{opacity:0;transform:translateY(4px)}to{opacity:1;transform:none}}\n@media (prefers-reduced-motion:reduce){.panel{animation:none}}\n\n/* ---- Section structure --------------------------------------------------- */\nsection{margin:var(--s7) 0}\n.eyebrow{display:block;font-family:var(--mono);font-size:12px;font-weight:600;letter-spacing:.18em;\n  text-transform:uppercase;color:var(--cobalt);margin-bottom:var(--s2)}\nh2{font-size:26px;font-weight:600;letter-spacing:-.01em;color:var(--ink);\n  border-bottom:1px solid var(--border);padding-bottom:var(--s3);margin:0 0 var(--s5);\n  display:flex;align-items:baseline;gap:var(--s2);flex-wrap:wrap}\nh3{font-size:20px;font-weight:600;margin:var(--s6) 0 var(--s3);color:var(--ink-soft)}\n.lead{font-size:19px;color:var(--ink-soft);max-width:var(--measure)}\n.prose{max-width:var(--measure)}\n.rule{border:0;border-top:1px solid var(--border);margin:var(--s6) 0}\n.rule--accent{border:0;height:3px;width:52px;border-radius:2px;background:var(--cobalt);margin:var(--s5) 0}\n\n/* ---- Stat / decision cards ---------------------------------------------- */\n.grid{display:grid;gap:var(--s4)}\n.grid.cards{grid-template-columns:repeat(auto-fit,minmax(220px,1fr))}\n.card{background:var(--panel);border:1px solid var(--border);border-radius:var(--r2);\n  padding:var(--s5);box-shadow:var(--shadow-1)}\n.card .k{font-family:var(--mono);font-size:11.5px;font-weight:500;letter-spacing:.09em;text-transform:uppercase;\n  color:var(--muted);display:flex;align-items:center;gap:6px;flex-wrap:wrap}\n.card .v{font-size:32px;font-weight:600;line-height:1.1;margin-top:var(--s2);\n  font-variant-numeric:tabular-nums;letter-spacing:-.02em}\n.card .v.mono{font-family:var(--mono);font-size:22px;letter-spacing:0}\n.card .v.pos{color:var(--teal-ink)} .card .v.neg{color:var(--vermillion-ink)}\n.card .note{font-size:14.5px;color:var(--muted);margin-top:var(--s2)}\n.card .plain{font-size:14.5px;color:var(--ink-soft);margin-top:var(--s2);line-height:1.45} /* plain-language subline */\n.card--optimal,.card--good{box-shadow:inset 0 3px 0 var(--cobalt),var(--shadow-1)}\n.card--positive{box-shadow:inset 0 3px 0 var(--teal),var(--shadow-1)}\n.card--caution{box-shadow:inset 0 3px 0 var(--amber),var(--shadow-1)}\n.card--risk,.card--warn{box-shadow:inset 0 3px 0 var(--vermillion),var(--shadow-1)}\n.card--neutral{box-shadow:inset 0 3px 0 var(--slate),var(--shadow-1)}\n\n/* ---- Verdict / hero block ------------------------------------------------ */\n.verdict{position:relative;background:var(--panel);border:1px solid var(--border);\n  border-left:4px solid var(--cobalt);border-radius:var(--r2);padding:var(--s5) var(--s6);\n  font-size:19px;box-shadow:var(--shadow-1)}\n.verdict--hero{padding:var(--s6) var(--s7)}\n.verdict__eyebrow{font-family:var(--mono);font-size:12px;font-weight:600;letter-spacing:.18em;\n  text-transform:uppercase;color:var(--cobalt);margin-bottom:var(--s3);display:block}\n.verdict__headline{font-size:clamp(22px,2.6vw,28px);font-weight:600;line-height:1.28;letter-spacing:-.01em;\n  color:var(--ink);margin:0 0 var(--s3);max-width:var(--measure)}\n.verdict__lead{font-size:19px;color:var(--ink-soft);margin:0;max-width:var(--measure)}\n.verdict__badges{display:flex;flex-wrap:wrap;gap:var(--s2);margin:var(--s4) 0 0}\n.verdict__meta{font-family:var(--mono);font-size:13px;color:var(--muted);margin-top:var(--s4);\n  padding-top:var(--s3);border-top:1px solid var(--hairline)}\n.verdict > .pill,.verdict > .badge{margin-bottom:var(--s3)}\n.verdict > p{margin:0;max-width:var(--measure)}\n\n/* ---- Answer strip (60-second tri-panel centrepiece) ---------------------- */\n.answer-strip{display:grid;grid-template-columns:repeat(3,1fr);gap:var(--s3);margin:0 0 var(--s6)}\n.answer{background:var(--panel);border:1px solid var(--border);border-left:5px solid var(--slate);\n  border-radius:var(--r2);padding:var(--s4) var(--s5);box-shadow:var(--shadow-1)}\n.answer-q{font-family:var(--mono);font-size:12px;letter-spacing:.06em;text-transform:uppercase;color:var(--muted)}\n.answer-a{font-size:24px;font-weight:600;line-height:1.25;margin-top:var(--s2);display:flex;align-items:baseline;gap:9px}\n.answer-ic{font-size:20px;line-height:1;flex:none}\n.answer--ok{border-left-color:var(--cobalt)}       .answer--ok .answer-a{color:var(--cobalt-ink)}\n.answer--added{border-left-color:var(--teal)}      .answer--added .answer-a{color:var(--teal-ink)}   /* teal = added value only */\n.answer--mid{border-left-color:var(--amber)}       .answer--mid .answer-a{color:var(--amber-ink)}\n.answer--warn{border-left-color:var(--vermillion)} .answer--warn .answer-a{color:var(--vermillion-ink)}\n.answer--neutral{border-left-color:var(--slate)}   .answer--neutral .answer-a{color:var(--ink)}\n@media(max-width:820px){.answer-strip{grid-template-columns:1fr}}\n\n/* ---- Pills & badges (icon + word, glyph auto-injected; never colour alone) */\n.pill,.badge{display:inline-flex;align-items:center;gap:.42em;vertical-align:middle;\n  font-family:var(--mono);font-size:12px;font-weight:600;line-height:1;letter-spacing:.02em;\n  padding:5px 11px 5px 9px;border-radius:var(--r-pill);border:1px solid transparent;white-space:nowrap}\n.pill::before,.badge::before{font-weight:700;font-size:1.02em;line-height:1}\n/* cobalt = standard/good/optimal/clean */\n.pill.ok,.pill.optimal,.badge--optimal,.badge--good{background:var(--cobalt-bg);border-color:var(--cobalt-line);color:var(--cobalt-ink)}\n.pill.ok::before,.pill.optimal::before,.badge--optimal::before,.badge--good::before{content:\"\\2713\\FE0E\";color:var(--cobalt)}\n/* teal = adds value / predictive */\n.pill.positive,.badge--positive{background:var(--teal-bg);border-color:var(--teal-line);color:var(--teal-ink)}\n.pill.positive::before,.badge--positive::before{content:\"\\271A\\FE0E\";color:var(--teal)}\n/* amber = caution / moderate */\n.pill.mid,.pill.caution,.badge--caution{background:var(--amber-bg);border-color:var(--amber-line);color:var(--amber-ink)}\n.pill.mid::before,.pill.caution::before,.badge--caution::before{content:\"\\25B3\\FE0E\";color:var(--amber-ink)}\n/* vermillion = risk / confounder / high concern */\n.pill.warn,.pill.risk,.badge--risk,.badge--warn{background:var(--vermillion-bg);border-color:var(--vermillion-line);color:var(--vermillion-ink)}\n.pill.warn::before,.pill.risk::before,.badge--risk::before{content:\"\\25B2\\FE0E\";color:var(--vermillion)}\n/* slate = neutral / redundant / single-modality */\n.pill.neutral,.badge--neutral{background:var(--slate-bg);border-color:var(--slate-line);color:var(--slate-ink)}\n.pill.neutral::before,.badge--neutral::before{content:\"\\2248\\FE0E\";color:var(--slate-ink)}\n.badge--bare::before{content:none}\n.tag-row{display:flex;flex-wrap:wrap;gap:var(--s2);align-items:center}\n\n/* ---- Callouts (\"What this means\" etc.) ----------------------------------- */\n.callout{position:relative;border:1px solid var(--border);border-left:4px solid var(--slate);\n  border-radius:var(--r1);padding:var(--s4) var(--s5);margin:var(--s4) 0;background:var(--panel);\n  font-size:17px;max-width:var(--measure)}\n.callout__label{display:inline-block;font-family:var(--mono);font-size:11px;font-weight:700;letter-spacing:.12em;\n  text-transform:uppercase;margin-bottom:var(--s2);color:var(--slate-ink)}\n.callout__body,.callout p{margin:0;color:var(--ink-soft)}\n.callout--means{border-left-color:var(--cobalt);background:var(--cobalt-bg)}\n.callout--means .callout__label{color:var(--cobalt-ink)}\n.callout--positive{border-left-color:var(--teal);background:var(--teal-bg)}\n.callout--positive .callout__label{color:var(--teal-ink)}\n.callout--watch{border-left-color:var(--amber);background:var(--amber-bg)}\n.callout--watch .callout__label{color:var(--amber-ink)}\n.callout--risk{border-left-color:var(--vermillion);background:var(--vermillion-bg)}\n.callout--risk .callout__label{color:var(--vermillion-ink)}\n.callout--note{border-left-color:var(--slate);background:var(--slate-bg)}\n\n/* ---- Info-icon tooltip (hover + focus; a11y-correct; keep OUT of overflow:auto) */\nbutton.info,.info{appearance:none;display:inline-flex;align-items:center;justify-content:center;\n  width:17px;height:17px;padding:0;border-radius:50%;border:1px solid var(--cobalt-line);\n  background:var(--cobalt-bg);color:var(--cobalt-ink);font-family:var(--mono);font-size:10px;font-weight:700;\n  font-style:normal;line-height:1;cursor:help;position:relative;vertical-align:middle;user-select:none;margin-left:.3em}\n.info::after{content:\"i\"}\n.info__bubble{position:absolute;bottom:calc(100% + 10px);left:50%;transform:translateX(-50%) translateY(4px);\n  width:max-content;max-width:280px;padding:10px 13px;border-radius:var(--r1);background:var(--ink);color:#F1F5F9;\n  font-family:var(--serif);font-size:14.5px;font-weight:400;line-height:1.45;letter-spacing:0;text-align:left;\n  text-transform:none;white-space:normal;box-shadow:var(--shadow-2);opacity:0;visibility:hidden;pointer-events:none;\n  transition:opacity .16s ease,transform .16s ease;z-index:50}\n.info__bubble strong{color:#fff;font-weight:600}\n.info__bubble::after{content:\"\";position:absolute;top:100%;left:50%;transform:translateX(-50%);\n  border:6px solid transparent;border-top-color:var(--ink)}\n.info:hover .info__bubble,.info:focus .info__bubble,.info:focus-within .info__bubble{\n  opacity:1;visibility:visible;transform:translateX(-50%) translateY(0)}\n.info:hover,.info:focus-visible{color:var(--cobalt);border-color:var(--cobalt)}\n.info--below .info__bubble{bottom:auto;top:calc(100% + 10px);transform:translateX(-50%) translateY(-4px)}\n.info--below .info__bubble::after{top:auto;bottom:100%;border-top-color:transparent;border-bottom-color:var(--ink)}\n.info--below:hover .info__bubble,.info--below:focus-within .info__bubble{transform:translateX(-50%) translateY(0)}\n\n/* ---- Reading guide / glossary (collapsible <details>) -------------------- */\n.reading-guide{background:var(--sunken);border:1px solid var(--border);border-radius:var(--r2);\n  margin:var(--s6) 0 var(--s5);overflow:hidden}\ndetails.reading-guide{padding:0}\ndetails.reading-guide>summary{list-style:none;cursor:pointer;padding:var(--s4) var(--s6);\n  font-size:19px;font-weight:600;color:var(--ink);display:flex;align-items:center;gap:10px;user-select:none}\ndetails.reading-guide>summary::-webkit-details-marker{display:none}\ndetails.reading-guide>summary::before{content:\"\\25B8\";color:var(--cobalt);font-size:14px;transition:transform .15s ease}\ndetails.reading-guide[open]>summary::before{transform:rotate(90deg)}\ndetails.reading-guide .gloss-body{padding:var(--s2) var(--s6) var(--s5);border-top:1px solid var(--border)}\n/* also allow non-collapsible use: plain .reading-guide div with padding */\n.reading-guide:not(details){padding:var(--s5) var(--s6)}\n.glossary{display:grid;grid-template-columns:minmax(150px,200px) 1fr;gap:var(--s2) var(--s5);margin:0}\n.glossary dt{font-family:var(--mono);font-size:13px;font-weight:600;color:var(--ink);padding-top:2px}\n.glossary dd{margin:0 0 var(--s2);font-size:16px;color:var(--ink-soft);line-height:1.5}\n@media (max-width:640px){.glossary{grid-template-columns:1fr;gap:2px var(--s2)}\n  .glossary dd{margin-bottom:var(--s3);padding-left:var(--s2);border-left:2px solid var(--border)}}\n\n/* ---- Figure legend key (colour -> meaning) ------------------------------- */\n.legend-row{display:flex;flex-wrap:wrap;gap:var(--s2) var(--s5);margin:var(--s3) 0;font-size:14px;color:var(--muted)}\n.legend-row .swatch{display:inline-flex;align-items:center;gap:6px}\n.legend-row .swatch::before{content:\"\";width:12px;height:12px;border-radius:3px;background:var(--slate);display:inline-block}\n.swatch.is-fusion::before{background:var(--cobalt)} .swatch.is-single::before{background:var(--slate)}\n.swatch.is-loo::before{background:var(--teal)} .swatch.is-control::before{background:var(--vermillion)}\n.swatch.is-caution::before{background:var(--amber)}\n\n/* ---- Modality utility ledger --------------------------------------------- */\n.ledger-item{border:1px solid var(--border);border-radius:var(--r2);padding:var(--s4) var(--s5);\n  margin-bottom:var(--s3);background:var(--panel);box-shadow:var(--shadow-1)}\n.ledger-head{display:flex;align-items:center;justify-content:space-between;gap:var(--s3);flex-wrap:wrap}\n.ledger-item .name,.ledger-name{font-weight:600;font-size:18px;color:var(--ink)}\n.ledger-verdict{font-size:15px;color:var(--muted);margin-top:2px}\n.ledger-item .muted,.ledger-stats{font-family:var(--mono);font-size:13px;color:var(--muted);margin-top:var(--s2)}\n.ledger-item .rec,.ledger-rec{color:var(--ink-soft);font-size:15.5px;margin-top:var(--s2)}\n\n/* ---- Flags list (colour + glyph) ----------------------------------------- */\n.flags{list-style:none;padding:0;margin:var(--s4) 0}\n.flags li{position:relative;padding:var(--s3) var(--s4) var(--s3) 42px;border:1px solid var(--border);\n  border-left:4px solid var(--amber);border-radius:var(--r1);margin-bottom:var(--s2);font-size:16px;\n  background:var(--panel);color:var(--ink-soft)}\n.flags li::before{content:\"\\25B3\\FE0E\";position:absolute;left:16px;top:50%;transform:translateY(-50%);\n  color:var(--amber-ink);font-family:var(--mono);font-weight:700}\n.flags li.clean{border-left-color:var(--teal)} .flags li.clean::before{content:\"\\2713\\FE0E\";color:var(--teal-ink)}\n.flags li.risk{border-left-color:var(--vermillion)} .flags li.risk::before{content:\"\\25B2\\FE0E\";color:var(--vermillion-ink)}\n\n/* ---- Recommendations ----------------------------------------------------- */\nul.recs{list-style:none;padding:0;margin:var(--s3) 0;max-width:var(--measure)}\nul.recs li{position:relative;padding-left:30px;margin-bottom:var(--s3);font-size:17px}\nul.recs li::before{content:\"\\2192\";position:absolute;left:4px;top:0;color:var(--cobalt);font-weight:700}\n\n/* ---- Figures ------------------------------------------------------------- */\n.figure{background:var(--panel);border:1px solid var(--border);border-radius:var(--r2);\n  padding:var(--s4) var(--s5);overflow-x:auto;box-shadow:var(--shadow-1)}\n.figcap{font-size:14.5px;color:var(--muted);margin:var(--s3) var(--s1) 0;max-width:var(--measure);line-height:1.5}\n.figcap b,.figcap strong{color:var(--ink-soft)}\n\n/* ---- Data tables --------------------------------------------------------- */\n.table-wrap{background:var(--panel);border:1px solid var(--border);border-radius:var(--r2);\n  padding:var(--s4);box-shadow:var(--shadow-1);margin-top:var(--s4)}\n.table-controls{display:flex;gap:var(--s3);margin-bottom:var(--s3);flex-wrap:wrap}\n.table-filter{flex:1;min-width:200px;font-family:var(--serif);font-size:15px;padding:9px 13px;\n  border:1px solid var(--border);border-radius:var(--r1);color:var(--ink);background:var(--panel)}\n.table-filter::placeholder{color:var(--faint)}\n.table-filter:focus{outline:none;border-color:var(--cobalt);box-shadow:0 0 0 3px var(--cobalt-bg)}\n.btn{font-family:var(--mono);font-size:12.5px;font-weight:600;letter-spacing:.02em;background:var(--cobalt);\n  color:#fff;border:none;border-radius:var(--r1);padding:9px 15px;cursor:pointer;transition:background .15s ease}\n.btn:hover{background:var(--cobalt-ink)} .btn:active{transform:translateY(1px)}\n.table-scroll{overflow-x:auto}\ntable.omicau-table{width:100%;border-collapse:collapse;font-size:14.5px}\ntable.omicau-table th{font-family:var(--mono);font-size:11px;text-transform:uppercase;letter-spacing:.06em;\n  color:var(--muted);text-align:left;padding:11px 12px;cursor:pointer;border-bottom:2px solid var(--border);\n  white-space:nowrap;user-select:none;position:sticky;top:0;background:var(--panel);transition:color .12s ease}\ntable.omicau-table th:hover{color:var(--ink)}\ntable.omicau-table td{padding:10px 12px;border-bottom:1px solid var(--hairline);color:var(--ink-soft)}\ntable.omicau-table td.num{font-family:var(--mono);text-align:right;font-variant-numeric:tabular-nums;color:var(--ink)}\ntable.omicau-table tbody tr:hover{background:var(--sunken)}\ntable.omicau-table tbody tr:last-child td{border-bottom:none}\n.sort-ind{margin-left:6px;color:var(--cobalt);font-size:.85em}\n\n/* ---- Workflow flowchart + config ----------------------------------------- */\n.flow{background:var(--panel);border:1px solid var(--border);border-radius:var(--r2);padding:var(--s6);box-shadow:var(--shadow-1)}\npre.config{background:var(--code-bg);color:var(--code-ink);font-family:var(--mono);font-size:12.5px;line-height:1.55;\n  padding:var(--s5);border-radius:var(--r2);overflow-x:auto;-webkit-overflow-scrolling:touch}\n\n/* ---- Utilities + footer -------------------------------------------------- */\n.muted{color:var(--muted)} .mono{font-family:var(--mono)}\n.legend{font-family:var(--mono);font-size:13px;color:var(--muted);margin-top:var(--s2)}\n.value--pos{color:var(--teal-ink)} .value--neg{color:var(--vermillion-ink)}\nfooter{border-top:1px solid var(--border);margin-top:var(--s8);padding-top:var(--s5);color:var(--muted);font-size:14px}\nfooter strong{color:var(--ink-soft)}\n\n/* ---- Responsive ---------------------------------------------------------- */\n@media (max-width:720px){\n  body{font-size:17px} .wrap{padding:0 var(--s4) var(--s7)} section{margin:var(--s6) 0}\n  .verdict,.verdict--hero{padding:var(--s5)} h2{font-size:23px}\n}\n\n/* ---- Print (emit both tabs, no chrome) ----------------------------------- */\n@media print{\n  :root{--bg:#fff;--panel:#fff;--sunken:#fff}\n  *{-webkit-print-color-adjust:exact;print-color-adjust:exact}\n  body{font-size:11pt;color:#000;background:#fff}\n  .wrap{max-width:none;padding:0}\n  .tabs,.table-controls,.sort-ind{display:none !important}\n  .panel{display:block !important;animation:none}\n  .panel + .panel{margin-top:var(--s7);border-top:2px solid var(--border);padding-top:var(--s6)}\n  details.reading-guide{padding:0} details.reading-guide .gloss-body{display:block !important}\n  .card,.figure,.ledger-item,.callout,.table-wrap,.verdict,.reading-guide,.flow,.answer{\n    box-shadow:none;break-inside:avoid;page-break-inside:avoid}\n  h2,h3{break-after:avoid;page-break-after:avoid}\n  table.omicau-table th{position:static}\n  pre.config{background:#fff;color:#000;border:1px solid var(--border)}\n  .info__bubble{display:none} a{color:#000;text-decoration:none}\n}"

TOOLTIP_JS = "/* ---- Append inside the existing <script>. Reveal is pure CSS (:hover/:focus/\n   :focus-within); this only adds Escape-to-dismiss and a touch-focus nudge.\n   The glossary needs NO JS (native <details>). --------------------------------- */\n\n// Escape dismisses the focused tooltip (works for the .info button trigger)\ndocument.addEventListener('keydown', function (e) {\n  if (e.key === 'Escape') {\n    var a = document.activeElement;\n    if (a && a.classList && a.classList.contains('info')) a.blur();\n  }\n});\n\n// Touch devices: tap focuses the button so :focus-within reveals the bubble,\n// without triggering any navigation or form submit.\ndocument.querySelectorAll('.info').forEach(function (b) {\n  b.addEventListener('click', function (e) { e.preventDefault(); });\n});"

GLOSSARY = {
    "AUROC": "A 0-to-1 score for telling two groups apart. 0.5 is a coin-flip; 1.0 is always right.",
    "R²": "A score for predicting a number. 0 is no better than guessing the average; 1.0 is perfect.",
    "Fusion gain (leave-one-out)": "How much the score rises when all data layers are combined versus the single best layer alone. Near zero means combining adds nothing.",
    "Redundancy (CKA)": "How alike two layers are, from 0 (unrelated) to 1 (near-identical). High overlap means one layer largely repeats another.",
    "Batch effect": "A technical signature from when or where samples were processed that a model can mistake for real biology.",
    "Missingness bias (MNAR)": "When which values are missing is itself informative, so gaps in the data can fake a real signal.",
    "Control baseline (shuffled target)": "The same model trained on scrambled labels. It should score near chance; if it beats chance, the pipeline is leaking.",
    "Group-aware cross-validation / leakage": "Keeping each patient's samples entirely in training or entirely in testing, never split across both, so scores are not secretly inflated.",
    "Provenance hash": "A SHA-256 fingerprint of the exact inputs and settings. If a byte changes, the hash changes, proving the report matches the data.",
    "Layer verdicts": "One word per data type: predictive (adds real signal), redundant (repeats another), batch-confounded (technical artifact), or control-like (no better than noise)."
}

